using sv_963706bd39c94fc4ac62506f4aa7b90f.Models;

namespace sv_963706bd39c94fc4ac62506f4aa7b90f.Services;

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> SeedData = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic Italian pizza with fresh mozzarella, basil, and San Marzano tomatoes.", 30),
            new(2, "Spaghetti Carbonara", "Creamy pasta with guanciale, Pecorino Romano, and black pepper.", 25),
            new(3, "Tiramisu", "Layered coffee-soaked ladyfingers with mascarpone cream.", 45),
        },
        [2] = new List<Recipe>
        {
            new(4, "Chicken Tikka Masala", "Grilled chicken in a rich, spiced tomato-cream sauce.", 50),
            new(5, "Palak Paneer", "Fresh spinach curry with cubes of soft paneer cheese.", 35),
            new(6, "Biryani", "Fragrant basmati rice layered with spiced meat and caramelized onions.", 60),
        },
        [3] = new List<Recipe>
        {
            new(7, "Kung Pao Chicken", "Stir-fried chicken with peanuts, chili peppers, and Sichuan peppercorns.", 25),
            new(8, "Mapo Tofu", "Silken tofu in a fiery sauce of doubanjiang, ground pork, and numbing spice.", 20),
            new(9, "Xiaolongbao", "Steamed soup dumplings filled with pork and rich broth.", 90),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        if (SeedData.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@using sv_963706bd39c94fc4ac62506f4aa7b90f.Models
@using sv_963706bd39c94fc4ac62506f4aa7b90f.Services
@implements IDisposable
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@inject NavigationManager Navigation

<PageTitle>Recipes</PageTitle>

<h1>Recipes — Cuisine @CuisineId</h1>

@if (_errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_errorMessage</p>
        <button class="btn btn-outline-danger" @onclick="Retry">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes…</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <p><em>Refreshing…</em></p>
    }

    <ul>
        @foreach (var recipe in GetSortedRecipes())
        {
            <li>
                <strong>@recipe.Title</strong> — @recipe.Description
                <span class="text-muted">(@recipe.PrepTimeMinutes min)</span>
            </li>
        }
    </ul>
}

@code {
    [Parameter] public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private bool _isRefreshing;
    private string? _errorMessage;
    private int _loadedCuisineId;

    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        // Only reload data when the cuisine changes, not when sort changes.
        if (_loadedCuisineId == CuisineId && _recipes is not null)
        {
            return;
        }

        await LoadRecipesAsync();
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request.
        await CancelPendingRequestAsync();

        _cts = new CancellationTokenSource();
        var token = _cts.Token;
        var targetCuisineId = CuisineId;

        _errorMessage = null;

        // If we already have data on screen, show the refreshing indicator
        // instead of replacing content with a loading placeholder.
        if (_recipes is not null)
        {
            _isRefreshing = true;
        }

        try
        {
            var result = await RecipeService.GetByCuisineAsync(targetCuisineId, token);

            _recipes = result;
            _loadedCuisineId = targetCuisineId;
            _isRefreshing = false;
        }
        catch (OperationCanceledException) when (token.IsCancellationRequested)
        {
            // Request was intentionally cancelled — do nothing.
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", targetCuisineId);
            _isRefreshing = false;
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", targetCuisineId);
            _isRefreshing = false;
            _errorMessage = "Something went wrong while loading recipes. Please try again.";
        }
    }

    private IEnumerable<Recipe> GetSortedRecipes()
    {
        if (_recipes is null) return Enumerable.Empty<Recipe>();

        return Sort?.ToLowerInvariant() switch
        {
            "newest" => _recipes.OrderByDescending(r => r.Id),
            "popular" => _recipes.OrderBy(r => r.PrepTimeMinutes),
            _ => _recipes,
        };
    }

    private async Task Retry()
    {
        await LoadRecipesAsync();
    }

    private async Task CancelPendingRequestAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }
}

